import React, { useMemo, useState, useEffect } from "react";
import { FiMenu, FiBell, FiMoon, FiSearch, FiSun, FiClock } from "react-icons/fi";
import NotificationDropdown from "./NotificationDropdown";

export default function Navbar({
  title,
  subtitle,
  onMenuClick,
  onOpenSearch,
  unreadCount,
  alerts,
  transactions,
  theme,
  onToggleTheme,
  currentUser,
}) {
  const [openNotifications, setOpenNotifications] = useState(false);
  const [currentTime, setCurrentTime] = useState("");

  useEffect(() => {
    const updateTime = () => {
      const now = new Date();
      setCurrentTime(now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    };
    updateTime();
    const interval = setInterval(updateTime, 60000);
    return () => clearInterval(interval);
  }, []);

  const recentTransactions = useMemo(() => [...transactions].sort((a, b) => b.date.localeCompare(a.date)).slice(0, 5), [transactions]);

  return (
    <header className="sticky top-0 z-30 border-b border-white/5 bg-white/70 px-4 py-4 backdrop-blur-md dark:border-white/5 dark:bg-slate-950/50 md:px-6 transition-colors duration-300">
      <div className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <button
            type="button"
            onClick={onMenuClick}
            className="rounded-xl border border-slate-200 p-2 text-slate-600 transition-all hover:bg-slate-50 dark:border-white/10 dark:text-slate-300 dark:hover:bg-white/5 lg:hidden"
          >
            <FiMenu size={18} />
          </button>
          <div>
            <h1 className="text-xl font-extrabold tracking-tight text-slate-800 dark:text-white md:text-2xl drop-shadow-sm">{title}</h1>
            <p className="text-xs font-medium text-slate-500 dark:text-slate-400 md:text-sm">{subtitle}</p>
          </div>
        </div>

        <div className="flex items-center gap-3 md:gap-4">
          <div className="hidden items-center gap-2 rounded-full border border-slate-200 bg-slate-50/50 px-4 py-2 hover:bg-slate-100 transition-colors dark:border-white/10 dark:bg-slate-900/50 dark:hover:bg-slate-800/50 md:flex cursor-pointer shadow-sm" onClick={onOpenSearch}>
            <FiSearch size={16} className="text-slate-400" />
            <input 
              readOnly 
              placeholder="Search tiles, suppliers..." 
              className="bg-transparent text-sm w-48 text-slate-600 dark:text-slate-200 placeholder:text-slate-400 focus:outline-none cursor-pointer"
            />
            <kbd className="ml-2 rounded bg-slate-200 px-1.5 py-0.5 text-[10px] font-semibold text-slate-500 dark:bg-slate-800 dark:text-slate-400">⌘K</kbd>
          </div>

          <div className="hidden lg:flex items-center gap-1.5 mr-2 text-xs font-medium text-slate-500 dark:text-slate-400">
            <FiClock size={12} />
            <span>Updated: {currentTime || 'Just now'}</span>
          </div>

          <button
            type="button"
            onClick={onToggleTheme}
            className="rounded-full bg-slate-100 p-2.5 text-slate-600 transition-all hover:bg-slate-200 hover:scale-105 active:scale-95 dark:bg-slate-800 dark:text-slate-200 dark:hover:bg-slate-700"
          >
            {theme === "dark" ? <FiSun size={18} /> : <FiMoon size={18} />}
          </button>
          <div className="relative">
            <button
              type="button"
              onClick={() => setOpenNotifications((value) => !value)}
              className="relative rounded-full bg-slate-100 p-2.5 text-slate-600 transition-all hover:bg-slate-200 hover:scale-105 active:scale-95 dark:bg-slate-800 dark:text-slate-200 dark:hover:bg-slate-700"
            >
              <FiBell size={18} />
              {unreadCount > 0 ? (
                <>
                  <span className="absolute -right-1 -top-1 inline-flex h-5 min-w-5 items-center justify-center rounded-full bg-gradient-to-r from-rose-500 to-pink-500 px-1.5 text-[10px] font-bold text-white shadow-lg shadow-rose-500/30">
                    {unreadCount}
                  </span>
                  <span className="absolute right-0 top-0 h-3 w-3 animate-ping rounded-full bg-rose-400 opacity-75"></span>
                </>
              ) : null}
            </button>
            <NotificationDropdown open={openNotifications} alerts={alerts} recentTransactions={recentTransactions} />
          </div>
          
          <div className="ml-1 flex items-center gap-3 border-l border-slate-200 pl-4 dark:border-white/10">
            <div className="hidden text-right md:block">
              <p className="text-sm font-bold text-slate-700 dark:text-white leading-tight">{currentUser?.name || "Premium User"}</p>
              <p className="text-[11px] font-medium uppercase tracking-wider text-slate-500 dark:text-sky-400">{currentUser?.role || "admin"}</p>
            </div>
            <div className="h-10 w-10 cursor-pointer rounded-full bg-gradient-to-tr from-sky-500 to-indigo-500 p-[2px] shadow-md shadow-indigo-500/20 transition-transform hover:scale-105">
              <div className="h-full w-full rounded-full border-2 border-white bg-slate-800 dark:border-slate-900 overflow-hidden relative">
                <div className="absolute inset-x-0 bottom-0 h-1/2 bg-white/20"></div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </header>
  );
}
