import React from "react";
import { NavLink, useNavigate } from "react-router-dom";
import {
  FiAlertTriangle,
  FiBox,
  FiGrid,
  FiLogOut,
  FiMapPin,
  FiRepeat,
  FiShoppingBag,
  FiTruck,
  FiUsers,
  FiActivity,
  FiClock,
} from "react-icons/fi";

const navItems = [
  { path: "/dashboard", label: "Dashboard", icon: FiGrid, roles: ["admin", "staff"] },
  { path: "/tiles", label: "Tiles", icon: FiBox, roles: ["admin", "staff"] },
  { path: "/inventory", label: "Inventory", icon: FiActivity, roles: ["admin", "staff"] },
  { path: "/suppliers", label: "Suppliers", icon: FiTruck, roles: ["admin", "staff"] },
  { path: "/warehouses", label: "Warehouses", icon: FiMapPin, roles: ["admin", "staff"] },
  { path: "/orders", label: "Orders", icon: FiShoppingBag, roles: ["admin", "staff"] },
  { path: "/transfers", label: "Transfers", icon: FiRepeat, roles: ["admin", "staff"] },
  { path: "/users", label: "Users", icon: FiUsers, roles: ["admin"] },
  { path: "/transactions", label: "Transactions", icon: FiActivity, roles: ["admin", "staff"] },
  { path: "/alerts", label: "Alerts", icon: FiAlertTriangle, roles: ["admin", "staff"] },
  { path: "/activity", label: "Activity Logs", icon: FiClock, roles: ["admin", "staff"] },
];

export default function Sidebar({ isOpen, onClose, onLogout, role = "staff" }) {
  const navigate = useNavigate();

  const handleLogout = () => {
    onLogout();
    navigate("/login");
  };

  return (
    <>
      {isOpen && (
        <button
          type="button"
          onClick={onClose}
          className="fixed inset-0 z-30 bg-slate-900/60 backdrop-blur-sm lg:hidden transition-opacity"
          aria-label="Close sidebar"
        />
      )}

      <aside
        className={`fixed inset-y-0 left-0 z-40 w-72 border-r border-slate-200 bg-white dark:border-white/5 dark:bg-[#060e1d] text-slate-800 dark:text-slate-200 transition-transform duration-300 ease-spring ${
          isOpen ? "translate-x-0" : "-translate-x-full"
        } lg:translate-x-0 shadow-2xl shadow-slate-900/10 dark:shadow-none`}
      >
        <div className="flex h-full flex-col p-5">
          <div className="mb-8 rounded-2xl bg-gradient-to-br from-indigo-500 via-purple-500 to-sky-500 p-5 text-white shadow-lg shadow-indigo-500/20 relative overflow-hidden group">
            <div className="absolute top-0 right-0 -mr-8 -mt-8 w-24 h-24 rounded-full bg-white/20 blur-2xl group-hover:bg-white/30 transition-colors"></div>
            <p className="text-[10px] font-bold uppercase tracking-[0.25em] text-white/80">TileFlow</p>
            <p className="mt-1 text-2xl font-black tracking-tight drop-shadow-md">Nexus</p>
          </div>

          <nav className="flex-1 space-y-1.5 overflow-y-auto px-1 custom-scrollbar">
            {navItems.filter((item) => item.roles.includes(role)).map((item) => {
              const Icon = item.icon;

              return (
                <NavLink
                  key={item.path}
                  to={item.path}
                  onClick={onClose}
                  className={({ isActive }) =>
                    `group relative flex items-center gap-3.5 rounded-xl px-4 py-3 text-sm font-semibold transition-all duration-300 ${
                      isActive
                        ? "bg-slate-900 text-white shadow-md shadow-slate-900/20 dark:bg-white/10 dark:text-white dark:shadow-sky-500/10 dark:border dark:border-white/10"
                        : "text-slate-500 hover:bg-slate-100 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-white/5 dark:hover:text-slate-100"
                    }`
                  }
                >
                  {({ isActive }) => (
                    <>
                      {isActive && (
                        <div className="absolute left-0 top-1/2 -ml-1 h-8 w-1.5 -translate-y-1/2 rounded-r-full bg-sky-500 shadow-[0_0_8px_rgba(14,165,233,0.8)]" />
                      )}
                      <Icon
                        size={18}
                        className={`transition-transform duration-300 ${
                          isActive ? "text-sky-400 scale-110" : "text-slate-400 group-hover:scale-110"
                        }`}
                      />
                      <span>{item.label}</span>
                    </>
                  )}
                </NavLink>
              );
            })}
          </nav>

          <button
            type="button"
            onClick={handleLogout}
            className="mt-6 flex items-center justify-center gap-2 rounded-xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm font-bold text-rose-600 transition-all hover:bg-rose-100 hover:scale-[1.02] active:scale-[0.98] dark:border-rose-500/20 dark:bg-rose-500/10 dark:text-rose-400 dark:hover:bg-rose-500/20"
          >
            <FiLogOut size={16} />
            Secure Logout
          </button>
        </div>
      </aside>
    </>
  );
}
